  ('pukao-e9ff7ca9-moex-00308', 'pukao-e9ff7ca9', 'pukao-e9ff7ca9-moex-112-d1a761c9', 'sub-pukao-e9ff7ca9-02', NULL, 'single_choice', '有關行政訴訟之都市計畫審查程序，下列敘述何者正確？', '["都市計畫審查程序以審查法規性質之都市計畫為限", "不服都市計畫之變更，應先提起訴願，未獲救濟始得提起都市計畫審查訴訟", "為維護公共利益，人民得依都市計畫審查程序請求變更都市計畫", "都市計畫發布機關收受起訴狀後，應在2個月內重新自我審查是否合法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:28+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "客家事務行政"}'::jsonb, NULL),
